{
  "schema_version": 1,
  "request_id": "rf-suggest-edit-cross-object-mixed-risk-reconnect-plus-pump-parameter-001",
  "project": "radishflow",
  "task": "suggest_flowsheet_edits",
  "status": "partial",
  "requires_confirmation": true,
  "summary": "当前围绕已选中的泵与其下游冷却器相关问题生成候选提案：一是为未连接的 cooler-outlet-81 提供最小的下游连接占位建议，二是对 pump-12 上有直接诊断支撑的压力目标与效率参数提出局部修正候选。",
  "answers": [
    {
      "summary": "针对 cooler-outlet-81 的断开连接错误以及 pump-12 的无效出口压力目标、超范围效率参数，提出仅限当前选中对象的可审查候选 patch。",
      "issues": [
        {
          "title": "cooler-outlet-81 缺少下游去向",
          "diagnosis": "Trim Cooler Outlet is not connected to any downstream consumer or export sink.",
          "severity": "error",
          "citations": [
            "diag-1",
            "flowdoc-stream-3",
            "snapshot-1"
          ]
        },
        {
          "title": "pump-12 出口压力目标低于入口压力",
          "diagnosis": "Recycle Pump outlet pressure target is lower than the inlet pressure.",
          "severity": "error",
          "citations": [
            "diag-2",
            "flowdoc-unit-1",
            "flowdoc-stream-1",
            "snapshot-1"
          ]
        },
        {
          "title": "pump-12 效率参数超出建议范围",
          "diagnosis": "Recycle Pump efficiency_percent=108 is outside the recommended operating range.",
          "severity": "warning",
          "citations": [
            "diag-3",
            "flowdoc-unit-1"
          ]
        }
      ],
      "proposed_actions": [
        {
          "action": "candidate_edit",
          "title": "为 cooler-outlet-81 添加下游连接占位",
          "target": {
            "type": "stream",
            "id": "cooler-outlet-81"
          },
          "rationale": "直接诊断表明该流股未连接到任何下游单元或导出端，且当前求解状态为 invalid_topology。基于现有证据只能提出最小的连接占位，而不能臆造具体下游设备。",
          "patch": {
            "connection_placeholder": {
              "stream_id": "cooler-outlet-81",
              "missing_endpoint": "downstream_consumer_or_export_sink",
              "suggested_resolution": "attach_to_existing_downstream_unit_or_define_export_sink"
            }
          },
          "risk_level": "high",
          "requires_confirmation": true,
          "citations": [
            "diag-1",
            "flowdoc-stream-3",
            "snapshot-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "将 pump-12 出口压力目标抬高至高于入口压力的待确认值",
          "target": {
            "type": "unit",
            "id": "pump-12"
          },
          "rationale": "已知 feed-81 压力为 190 kPa，而 pump-12 当前 outlet_pressure_target_kpa 为 150 kPa，直接触发无效压力目标诊断。由于未提供设计压升或下游约束，适合先用高于入口压力的占位规格替代当前明显无效值。",
          "patch": {
            "spec_placeholders": [
              {
                "path": "config.outlet_pressure_target_kpa",
                "constraint": "> 190",
                "reason": "must exceed inlet stream pressure on feed-81"
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-2",
            "flowdoc-unit-1",
            "flowdoc-stream-1",
            "snapshot-1"
          ]
        },
        {
          "action": "candidate_edit",
          "title": "将 pump-12 效率参数替换为建议范围内占位值",
          "target": {
            "type": "unit",
            "id": "pump-12"
          },
          "rationale": "当前 efficiency_percent=108 已有直接超范围告警支撑，但请求中未给出更具体设计值，因此仅建议替换为建议范围内的待确认参数占位。",
          "patch": {
            "parameter_placeholders": [
              {
                "path": "config.efficiency_percent",
                "constraint": "within recommended operating range and < 108",
                "current_value": 108
              }
            ]
          },
          "risk_level": "medium",
          "requires_confirmation": true,
          "citations": [
            "diag-3",
            "flowdoc-unit-1"
          ]
        }
      ],
      "confidence": 0.89,
      "citations": [
        "diag-1",
        "diag-2",
        "diag-3",
        "flowdoc-stream-3",
        "flowdoc-unit-1",
        "flowdoc-stream-1",
        "snapshot-1"
      ]
    }
  ]
}
